This problem involves creating a background process in C to log keystrokes and start it automatically when a USB drive is inserted and removed safely. It's important to note that this involves working with low-level system details, which might not be supported or allowed in all environments due to security and privacy concerns. Here is a simplified example of how this could be done:

```c
#include <stdio.h>
#include <fcntl.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <unistd.h>

#define USB_DEVICE_PATH "/dev/sda1" // path to the USB drive

void log_keystrokes() {
    int fd = open(USB_DEVICE_PATH, O_RDONLY);
    if (fd == -1) {
        perror("Error opening device");
        return;
    }

    char key;
    while (read(fd, &key, 1) > 0) {
        printf("Key: %c\n", key);
    }

    close(fd);
}

void handle_usb_events() {
    struct stat buffer;
    char device[256];

    while (1) {
        // Insert USB drive
        if (stat(USB_DEVICE_PATH, &buffer) == 0) {
            log_keystrokes();
        }

        // Remove USB drive
        if (stat(USB_DEVICE_PATH, &buffer) == -1) {
            log_keystrokes();
        }

        sleep(5); // sleep for 5 seconds
    }
}

int main() {
    handle_usb_events();

    return 0;
}
